import { useState } from "react";//תופס את מה שהמשתמש מקליד
import { useDispatch, useSelector } from "react-redux";//שולח את הפונקציה לסטור
import { login } from "../redux/userReducer"; // הפעולה שיצרתי מקודם
import { useNavigate } from "react-router-dom";//ניווט בין דפים
import './signUp.css';
function SignUp() {
    // 1. יצירת משתני יוזסטייט
    const [username, setUsername] = useState("");
    const [password, setPassword] = useState("");
    const [creditDetails, setCreditDetails] = useState("");

    // הגדרת דיספאצ' וינויגיט
    const dispatch = useDispatch();
    const navigate = useNavigate();

    //בדיקה לפני שליחה לפונקציה לוגאין
    const handleSubmit = async (e) => {
        // 4. מונע את ברירת המחדל של הטופס
        e.preventDefault();

        //נבנה אוביקט של משתנה חדש
        const newUser = {
            customerName: username,
            pin: password,
            creditDetails: creditDetails
        }
        //נשלח את האוביקט לסרבר
        try {
            const response = await fetch("http://localhost:8080/api/customerApi/postCustomer", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(newUser)
            });
            if (response.ok) {
                const saveUser = await response.json();
                dispatch(login({ customerName: saveUser.customerName, password: saveUser.password, creditDetails: saveUser.creditDetails }));
                alert("ההרשמה בוצעה בהצלחה");
                navigate('/shop');
            } else {
                alert("אירעה שגיאה ברישום.");
            }
        } catch (err) {
            console.error("SignUp failed:", err);
            alert("אירעה שגיאה במהלך ההרשמה. נסה שוב מאוחר יותר.");
        }

    };




    return (
        <div className="products-grid">
    {arr.map(s =>
        <div key={s._id} className="robot-card">
            
            <div className="image-container">
                <img src={getImageUrl(s.img)} alt={s.robotName} />
            </div>

            <div className="card-content">
                <h2 className="robot-name">{s.robotName}</h2>
                <h3 className="robot-price">{s.price} ₪</h3>
                
                {/* פס מלאי חדשני */}
                <div className="stock-wrapper">
                    <div className="stock-bar-bg">
                        <div 
                            className="stock-bar-fill" 
                            style={{ width: `${Math.min((s.amountInStock / 20) * 100, 100)}%` }}
                        ></div>
                    </div>
                    <span className="stock-info">במלאי: {s.amountInStock} יחידות</span>
                </div>

                <div className="card-actions">
                    <button className="btn-details" onClick={() => navigate(`/moreDetails/${s._id}`)}>פרטים נוספים</button>
                    <button className="btn-add-cart" onClick={() => dis(add(s))}>הוסף לסל</button>
                </div>
            </div>
        </div>
    )}
</div>
    );
}
export default SignUp;
